Here are the public test cases for feature1_url_routing:
{
  "description": "Resolve a source URL string to a backend category and the routing-relevant fields the router derives from it; reject malformed URLs and unknown schemes.",
  "cases": [
    {
      "input": {
        "op": "route",
        "url": "file:///tmp"
      },
      "expected_output": "backend=file\n"
    },
    {
      "input": {
        "op": "route",
        "url": "http://example.com/path"
      },
      "expected_output": "backend=http\nhost=example.com\npath=/path\n"
    },
    {
      "input": {
        "op": "route",
        "url": "git+ssh://localhost:1234/foo/bar.git//baz#refs/tags/foo"
      },
      "expected_output": "backend=git\nrepo_scheme=ssh\nroot=/baz\n"
    },
    {
      "input": {
        "op": "route",
        "url": "s3://foo/bar"
      },
      "expected_output": "backend=blob\nscheme=s3\nroot=bar\n"
    },
    {
      "input": {
        "op": "route",
        "url": "unsupported://scheme"
      },
      "expected_output": "error=unsupported_scheme\nscheme=unsupported\n"
    },
    {
      "input": {
        "op": "route",
        "url": "bad*:url//bogus"
      },
      "expected_output": "error=invalid_url\n"
    }
  ]
}

Here are the public test cases for feature2_repo_path_split:
{
  "description": "Split a source path into the repository portion and the in-repository subpath, delimited by a doubled slash; when no delimiter is present the whole path is the repository and the subpath is root.",
  "cases": [
    {
      "input": {
        "op": "split_path",
        "path": "/hairyhenderson/gomplate//docs-src/content/functions/aws.yml"
      },
      "expected_output": "repo=/hairyhenderson/gomplate\nsubpath=/docs-src/content/functions/aws.yml\n"
    },
    {
      "input": {
        "op": "split_path",
        "path": "/foo//bar/baz"
      },
      "expected_output": "repo=/foo\nsubpath=/bar/baz\n"
    },
    {
      "input": {
        "op": "split_path",
        "path": "/repo"
      },
      "expected_output": "repo=/repo\nsubpath=/\n"
    },
    {
      "input": {
        "op": "split_path",
        "path": "//foo/bar"
      },
      "expected_output": "repo=\nsubpath=/foo/bar\n"
    }
  ]
}

Here are the public test cases for feature3_git_ref_resolution:
{
  "description": "Derive a fully-qualified version-control reference name from a source URL fragment: a bare name becomes a branch reference, a fragment already starting with the reference prefix is preserved verbatim, and no fragment yields an empty reference.",
  "cases": [
    {
      "input": {
        "op": "resolve_ref",
        "url": "git://localhost:1234/foo/bar.git//baz"
      },
      "expected_output": "ref=\n"
    },
    {
      "input": {
        "op": "resolve_ref",
        "url": "git+http://localhost:1234/foo/bar.git//baz#mybranch"
      },
      "expected_output": "ref=refs/heads/mybranch\n"
    },
    {
      "input": {
        "op": "resolve_ref",
        "url": "git+ssh://localhost:1234/foo/bar.git//baz#refs/tags/foo"
      },
      "expected_output": "ref=refs/tags/foo\n"
    }
  ]
}

Here are the public test cases for feature4_git_auth_selection:
{
  "description": "Choose an authentication method for a version-control source. URL userinfo provides basic credentials; environment variables can supply a password, a bearer token, or a private key; schemes without credentials select no authentication. The chosen method is reported as a neutral kind plus any user/secret fields.",
  "cases": [
    {
      "input": {
        "op": "select_auth",
        "url": "file:///bare.git"
      },
      "expected_output": "kind=none\n"
    },
    {
      "input": {
        "op": "select_auth",
        "url": "https://user:swordfish@example.com/foo"
      },
      "expected_output": "kind=basic\nuser=user\nsecret=swordfish\n"
    },
    {
      "input": {
        "op": "select_auth",
        "url": "https://user@example.com/foo",
        "env": {
          "GIT_HTTP_TOKEN": "mytoken"
        }
      },
      "expected_output": "kind=token\nsecret=mytoken\n"
    },
    {
      "input": {
        "op": "select_auth",
        "url": "ssh://git@example.com/foo",
        "env": {
          "GIT_SSH_KEY": ""
        }
      },
      "expected_output": "kind=ssh_key\nuser=git\n"
    }
  ]
}

Here are the public test cases for feature5_bucket_url_normalization:
{
  "description": "Sanitize an object-storage URL by retaining only the query parameters meaningful to the storage backend and discarding all others; the remaining parameters are re-encoded in canonical order.",
  "cases": [
    {
      "input": {
        "op": "normalize_url",
        "url": "s3://foo/bar/baz?type=hello/world"
      },
      "expected_output": "url=s3://foo/bar/baz\n"
    },
    {
      "input": {
        "op": "normalize_url",
        "url": "s3://foo/bar/baz?disableSSL=true&type=text/csv"
      },
      "expected_output": "url=s3://foo/bar/baz?disableSSL=true\n"
    },
    {
      "input": {
        "op": "normalize_url",
        "url": "gs://foo/bar/baz?private_key_path=key.json&foo=bar&access_id=abcd"
      },
      "expected_output": "url=gs://foo/bar/baz?access_id=abcd&private_key_path=key.json\n"
    }
  ]
}

Here are the public test cases for feature6_env_value_resolution:
{
  "description": "Resolve a configuration value by key: prefer the directly-set value, otherwise read and trim the contents of the file named by the '<KEY>_FILE' indirection, otherwise fall back to the supplied default (or empty).",
  "cases": [
    {
      "input": {
        "op": "getenv",
        "key": "FOOBARBAZ"
      },
      "expected_output": "value=\n"
    },
