      "input": {
        "op": "getenv",
        "key": "BLAHBLAH",
        "default": "default value"
      },
      "expected_output": "value=default value\n"
    },
    {
      "input": {
        "op": "getenv",
        "key": "FOO",
        "default": "bar",
        "file_content": "foo"
      },
      "expected_output": "value=foo\n"
    },
    {
      "input": {
        "op": "getenv",
        "key": "FOO",
        "default": "bar",
        "file_missing": true
      },
      "expected_output": "value=bar\n"
    }
  ]
}

